      "content": "// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = require('../../lib/id').projectsStore;

module.exports = {
  getTasksByStatus(projectId, status) {
    const project = projectsStore.get(projectId);
    if (!project) return null;
    return project.tasks.filter(task => task.status === status);
  },

  createTask(projectId, { message }) {
    const project = projectsStore.get(projectId);
    if (!project) return null;
    const taskId = randomUUID();
    const newTask = { id: taskId, message, status: 'todo' };
    project.tasks.push(newTask);
    return newTask;
  },

  updateTaskStatus(projectId, taskId, status) {
    if (status !== 'todo' && status !== 'done') return null;
    const project = projectsStore.get(projectId);
    if (!project) return null;
    const task = project.tasks.find(t => t.id === taskId);
    if (!task) return null;
    task.status = status;
    return task;
  }
};
